using System;

[AttributeUsage(AttributeTargets.All)]
public class TestableAttr : Attribute
{
    public TestableAttr() { }
}

[AttributeUsage(AttributeTargets.All)]
public class OtherAttr : Attribute
{
    public OtherAttr() { }
}

[TestableAttr]
[OtherAttr]
public interface IDataService
{
    string GetData(int id);
}

[YS.Knife.ExposeApi(typeof(IDataService), TypeAttributePatterns = new string[] { "Test*" })]
public class TestController
{
}

